namespace sv_c107b17658f2405dbd72caca92530f38.Client.Models;

public sealed class Shipment
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public DateTimeOffset? EstimatedDelivery { get; init; }
    public required IReadOnlyList<StatusUpdate> StatusUpdates { get; init; }
}

public sealed class StatusUpdate
{
    public required string Description { get; init; }
    public required DateTimeOffset Timestamp { get; init; }
    public string? Location { get; init; }
}

using sv_c107b17658f2405dbd72caca92530f38.Client.Models;

namespace sv_c107b17658f2405dbd72caca92530f38.Client.Services;

public interface IShipmentService
{
    Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_c107b17658f2405dbd72caca92530f38.Client.Models;
using sv_c107b17658f2405dbd72caca92530f38.Client.Services;

namespace sv_c107b17658f2405dbd72caca92530f38.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new Shipment
        {
            TrackingNumber = "TRK-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Timestamp = new DateTimeOffset(2026, 5, 22, 9, 0, 0, TimeSpan.Zero), Location = "New York, NY" },
                new StatusUpdate { Description = "Departed facility", Timestamp = new DateTimeOffset(2026, 5, 23, 6, 30, 0, TimeSpan.Zero), Location = "New York, NY" },
                new StatusUpdate { Description = "Arrived at sorting center", Timestamp = new DateTimeOffset(2026, 5, 24, 14, 15, 0, TimeSpan.Zero), Location = "Chicago, IL" },
            ]
        },
        ["TRK-002"] = new Shipment
        {
            TrackingNumber = "TRK-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 24, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Timestamp = new DateTimeOffset(2026, 5, 20, 10, 0, 0, TimeSpan.Zero), Location = "Seattle, WA" },
                new StatusUpdate { Description = "In transit", Timestamp = new DateTimeOffset(2026, 5, 21, 8, 0, 0, TimeSpan.Zero), Location = "Portland, OR" },
                new StatusUpdate { Description = "Out for delivery", Timestamp = new DateTimeOffset(2026, 5, 24, 7, 0, 0, TimeSpan.Zero), Location = "San Francisco, CA" },
                new StatusUpdate { Description = "Delivered", Timestamp = new DateTimeOffset(2026, 5, 24, 11, 32, 0, TimeSpan.Zero), Location = "San Francisco, CA" },
            ]
        },
        ["TRK-003"] = new Shipment
        {
            TrackingNumber = "TRK-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 30, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Order received", Timestamp = new DateTimeOffset(2026, 5, 25, 8, 0, 0, TimeSpan.Zero), Location = "Dallas, TX" },
            ]
        },
    };

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
    }
}

using System.Net.Http.Json;
using sv_c107b17658f2405dbd72caca92530f38.Client.Models;

namespace sv_c107b17658f2405dbd72caca92530f38.Client.Services;

/// <summary>
/// HTTP-based implementation used when running on WebAssembly.
/// Calls the server API endpoint to get shipment data.
/// </summary>
public sealed class ShipmentApiClient(HttpClient httpClient) : IShipmentService
{
    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
        {
            throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
        }

        response.EnsureSuccessStatusCode();

        return await response.Content.ReadFromJsonAsync<Shipment>(ct)
            ?? throw new InvalidOperationException("Received empty response from server.");
    }
}

